let questions = verified;

const topics = {
    "space": "Space Science",
    "biology": "Biology",
    "earth": "Earth Science",
    "chemistry": "Chemistry",
    "physics": "Physics",
    "math": "Math",
    "integers": "Integers"
};

for (let topic in topics) {
    for (let difficulty of ["easy", "medium", "hard"]) {
        if (!Object.keys(unverified[difficulty]).includes(topic)) continue;
        questions[difficulty][topic] = Object.keys(questions[difficulty]).includes(topic) ? questions[difficulty][topic].concat(unverified[difficulty][topic]) : unverified[difficulty][topic];
    }
}

let total = 0;

for (let topic in topics) {
    if (topic == "integers") continue;
    for (let difficulty of ["easy", "medium", "hard"]) {
        for (let i = 0; i < questions[difficulty][topic].length; i++) {
            let question = questions[difficulty][topic][i];
            // total += (2 * question[1][0].length + 2 * question[1][1].length + question[1][2].length) * (question[2].reduce((accumulator, choice) => accumulator * (Array.isArray(choice) ? choice.length + 1 : 2), 1) - 1 - question[2].reduce((accumulator, choice) => accumulator + (Array.isArray(choice) ? choice.length : 1), 0));
            total += question[1][0].length + question[1][1].length + question[1][2].length;
        }
    }
}

tot.textContent = total;